diff --git a/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp b/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
index 2d7524e8018b..75f15a194635 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
@@ -3579,7 +3579,46 @@ Value *InstCombinerImpl::foldAndOrOfICmps(ICmpInst *LHS, ICmpInst *RHS,
     return Builder.createIsFPClass(X, IsAnd ? FPClassTest::fcNormal
                                             : ~FPClassTest::fcNormal);

-  return foldAndOrOfICmpsUsingRanges(LHS, RHS, IsAnd);
+  if (Value *V = foldAndOrOfICmpsUsingRanges(LHS, RHS, IsAnd))
+    return V;
+
+  if (std::optional<bool> Implied = isImpliedCondition(RHS, LHS, DL, IsAnd)) {
+    if (*Implied)
+      return IsAnd ? RHS : LHS;
+  }
+  if (std::optional<bool> Implied = isImpliedCondition(LHS, RHS, DL, IsAnd)) {
+    if (*Implied)
+      return IsAnd ? LHS : RHS;
+  }
+
+  // (icmp ult X, C1) & (icmp eq (X & Mask), C2) -> (icmp eq (X & Mask), C2)
+  // If (X & Mask) == C2 implies X < C1, we can return RHS.
+  auto checkRangeImplied = [&](Value *CmpA0, CmpInst::Predicate PredA, const APInt &CA,
+                               Value *CmpB0, CmpInst::Predicate PredB, const APInt &CB) -> bool {
+    Value *X;
+    const APInt *Mask;
+    if (match(CmpA0, m_And(m_Value(X), m_APInt(Mask))) && X == CmpB0) {
+      if (PredA == CmpInst::ICMP_EQ) {
+        if ((CA & ~(*Mask)) != 0) return false;
+        APInt MaxVal = CA | ~(*Mask);
+        APInt MinVal = CA;
+        ConstantRange CRB = ConstantRange::makeSatisfyingICmpRegion(PredB, CB);
+        if (CRB.contains(ConstantRange::getNonEmpty(MinVal, MaxVal + 1)))
+          return true;
+      }
+    }
+    return false;
+  };
+
+  if (IsAnd) {
+    if (checkRangeImplied(LHS0, PredL, *LHSC, RHS0, PredR, *RHSC)) return LHS;
+    if (checkRangeImplied(RHS0, PredR, *RHSC, LHS0, PredL, *LHSC)) return RHS;
+  } else {
+    if (checkRangeImplied(LHS0, ICmpInst::getInversePredicate(PredL), *LHSC,
+                          RHS0, ICmpInst::getInversePredicate(PredR), *RHSC)) return LHS;
+    if (checkRangeImplied(RHS0, ICmpInst::getInversePredicate(PredR), *RHSC,
+                          LHS0, ICmpInst::getInversePredicate(PredL), *LHSC)) return RHS;
+  }
 }

 /// If IsLogical is true, then the and/or is in select form and the transform
@@ -3587,8 +3626,6 @@ Value *InstCombinerImpl::foldAndOrOfICmps(ICmpInst *LHS, ICmpInst *RHS,
 Value *InstCombinerImpl::foldBooleanAndOr(Value *LHS, Value *RHS,
                                           Instruction &I, bool IsAnd,
                                           bool IsLogical) {
-  if (!LHS->getType()->isIntOrIntVectorTy(1))
-    return nullptr;

   // handle (roughly):
   // (icmp ne (A & B), C) | (icmp ne (A & D), E)

